from matplotlib import pyplot as pltfrom skimage import io, filters, featurefrom skimage.color import rgb2grayimport cv2import numpy as npimg = io.imread("../data/BSE_Google.jpg", 0)from skimage.filters import roberts, sobel, scharr, prewitt, faridroberts_img = roberts(img)sobel_img = sobel(img)scharr_img = scharr(img)prewitt_img = prewitt(img)farid_img = farid(img)plt.figure()plt.subplot(1,2,1)plt.imshow(img, cmap = "gray")plt.title("Original")plt.subplot(1,2,2)plt.imshow(roberts_img, cmap = "gray")plt.title("roberts_img")plt.figure()plt.subplot(1,2,1)plt.imshow(sobel_img, cmap = "gray")plt.title("sobel_img")plt.subplot(1,2,2)plt.imshow(scharr_img, cmap = "gray")plt.title("scharr_img")plt.figure()plt.subplot(1,2,1)plt.imshow(prewitt_img, cmap = "gray")plt.title("prewitt_img")plt.subplot(1,2,2)plt.imshow(farid_img, cmap = "gray")plt.title("farid_img")